@RestController
@RequestMapping("/saml")
class SamlController {
    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public ResponseEntity<String> metadata() throws Exception {
        return ResponseEntity.ok(samlService.buildMetadata());
    }

    @GetMapping("/login")
    public void login(@RequestParam(value = "relayState", required = false) String relayState, HttpServletResponse response) throws Exception {
        String authnRequest = samlService.buildAuthnRequest(relayState);
        response.setContentType(MediaType.TEXT_HTML_VALUE);
        response.getWriter().write("<html><body onload=\"document.forms[0].submit()\">" +
                "<form method=\"post\" action=\"" + escapeHtml("https://idp.example.com/sso") + "\">" +
                "<input type=\"hidden\" name=\"SAMLRequest\" value=\"" + escapeHtml(Base64.getEncoder().encodeToString(authnRequest.getBytes(StandardCharsets.UTF_8))) + "\"/>" +
                (relayState != null ? "<input type=\"hidden\" name=\"RelayState\" value=\"" + escapeHtml(relayState) + "\"/>" : "") +
                "</form></body></html>");
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<String> acs(@RequestParam("SAMLResponse") String samlResponse, @RequestParam(value = "RelayState", required = false) String relayState) throws Exception {
        Assertion assertion = samlService.parseAndValidateResponse(samlResponse, relayState);
        String subject = assertion.getSubject().getNameID().getValue();
        return ResponseEntity.ok("Authenticated user: " + subject);
    }

    @GetMapping("/slo")
    public ResponseEntity<String> slo() {
        return ResponseEntity.ok("SLO endpoint");
    }

    private String escapeHtml(String input) {
        return input == null ? "" : input.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace("\"", "&quot;");
    }
}